    PacketSender:sendLuaCommonData(rakssid, "WatcherInfo", name)
end

function PacketSender:sendFollowerInfo(rakssid, name)
    PacketSender:sendLuaCommonData(rakssid, "FollowerInfo", name)
end

function PacketSender:sendDataReport(rakssid, main, child)
    local reportData = {
        mainEvent = main or "",
        childEvent = child or "",
    }
    local data = DataBuilder.new():fromTable(reportData):getData()
    PacketSender:sendServerCommonData(rakssid, "DataReport", "", data)
end

return PacketSender